import React, { useState } from 'react';
import { motion } from 'framer-motion';
import axios from 'axios';

const Dashboard = () => {
  const [preview, setPreview] = useState(null);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    setPreview(URL.createObjectURL(file));
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('mode', 'segmentation');

    try {
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Ensure Flask is running on port 5000");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', background: '#F5F7FA', minHeight: '100vh' }}>
      <h1 style={{ color: '#1E88E5' }}>Diagnostic Comparison Viewer</h1>
      <input type="file" onChange={handleUpload} style={{ marginBottom: '20px' }} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
        {/* Original Side */}
        <div style={{ background: '#000', borderRadius: '15px', overflow: 'hidden' }}>
          {preview && <img src={preview} style={{ width: '100%' }} alt="Original" />}
        </div>

        {/* AI Overlay Side (The Green Marks) */}
        <div style={{ background: '#000', borderRadius: '15px', overflow: 'hidden', position: 'relative' }}>
          {preview && <img src={preview} style={{ width: '100%' }} alt="Base" />}
          {data?.mask && (
            <motion.img 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 0.6 }} 
              src={data.mask} 
              style={{ 
                position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
                filter: 'hue-rotate(90deg) saturate(10) brightness(1.2)' 
              }} 
            />
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
